```class Solution {
public:
    int longestPalindrome(string s, string t) {
        int n = s.size(), m = t.size();
        int res = 0;
        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= m; j++) {
                string ss = s.substr(0, i);
                string tt = t.substr(0, j);
                string concat = ss + tt;
                string rev = concat;
                reverse(rev.begin(), rev.end());
                if (concat == rev) {
                    res = max(res, (int)concat.size());
                }
            }
        }
        return res;
    }
};```
